import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import AdminUserManagement from "./adminuser";
import "./admindashboard.css";
import Notifications from "./Notifications";
import University from "./University";
import Bachelors from "./Bachelors";
import Masters from "./Masters";
import PhD from "./PhD";
import StudentAnalytics from "./StudentAnalytics";

// ── Inline SVG icons ──────────────────────────────────────────────────────────
const LOGO_URI = "data:image/svg+xml;base64,";

const icons = {
  dashboard: (color="#64748b") => (
    <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <rect x="3" y="3" width="7" height="7" rx="1.5"/>
      <rect x="14" y="3" width="7" height="7" rx="1.5"/>
      <rect x="3" y="14" width="7" height="7" rx="1.5"/>
      <rect x="14" y="14" width="7" height="7" rx="1.5"/>
    </svg>
  ),
  users: (color="#64748b") => (
    <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <circle cx="9" cy="7" r="4"/>
      <path d="M3 21v-2a4 4 0 0 1 4-4h4a4 4 0 0 1 4 4v2"/>
      <path d="M16 3.13a4 4 0 0 1 0 7.75"/>
      <path d="M21 21v-2a4 4 0 0 0-3-3.87"/>
    </svg>
  ),
  university: (color="#64748b") => (
    <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M3 21h18"/>
      <path d="M5 21V7l7-4 7 4v14"/>
      <path d="M9 21v-4h6v4"/>
    </svg>
  ),
  bachelors: (color="#64748b") => (
    <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M22 10v6M2 10l10-5 10 5-10 5z"/>
      <path d="M6 12v5c3 3 9 3 12 0v-5"/>
    </svg>
  ),
  masters: (color="#64748b") => (
    <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M4 19.5A2.5 2.5 0 0 1 6.5 17H20"/>
      <path d="M6.5 2H20v20H6.5A2.5 2.5 0 0 1 4 19.5v-15A2.5 2.5 0 0 1 6.5 2z"/>
      <line x1="9" y1="7" x2="15" y2="7"/>
      <line x1="9" y1="11" x2="15" y2="11"/>
    </svg>
  ),
  phd: (color="#64748b") => (
    <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <circle cx="12" cy="12" r="10"/>
      <polyline points="12 6 12 12 16 14"/>
    </svg>
  ),
  analytics: (color="#64748b") => (
    <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <line x1="18" y1="20" x2="18" y2="10"/>
      <line x1="12" y1="20" x2="12" y2="4"/>
      <line x1="6" y1="20" x2="6" y2="14"/>
      <line x1="2" y1="20" x2="22" y2="20"/>
    </svg>
  ),
  notifications: (color="#64748b") => (
    <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M18 8A6 6 0 0 0 6 8c0 7-3 9-3 9h18s-3-2-3-9"/>
      <path d="M13.73 21a2 2 0 0 1-3.46 0"/>
    </svg>
  ),
  settings: (color="#64748b") => (
    <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <circle cx="12" cy="12" r="3"/>
      <path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1-2.83 2.83l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-4 0v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83-2.83l.06-.06A1.65 1.65 0 0 0 4.68 15a1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1 0-4h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 2.83-2.83l.06.06A1.65 1.65 0 0 0 9 4.68a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 4 0v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 2.83l-.06.06A1.65 1.65 0 0 0 19.4 9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 0 4h-.09a1.65 1.65 0 0 0-1.51 1z"/>
    </svg>
  ),
  logout: (
    <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4"/>
      <polyline points="16 17 21 12 16 7"/>
      <line x1="21" y1="12" x2="9" y2="12"/>
    </svg>
  ),
  collapse: (
    <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
      <polyline points="15 18 9 12 15 6"/>
    </svg>
  ),
  expand: (
    <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
      <polyline points="9 18 15 12 9 6"/>
    </svg>
  ),
  search: (
    <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="#94a3b8" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/>
    </svg>
  ),
  bell: (
    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#f59e0b" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M18 8A6 6 0 0 0 6 8c0 7-3 9-3 9h18s-3-2-3-9"/>
      <path d="M13.73 21a2 2 0 0 1-3.46 0"/>
    </svg>
  ),
  hamburger: (
    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <line x1="3" y1="6" x2="21" y2="6"/><line x1="3" y1="12" x2="21" y2="12"/><line x1="3" y1="18" x2="21" y2="18"/>
    </svg>
  ),
};

const AdminDashboard = () => {
  const navigate = useNavigate();
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [activeTab, setActiveTab] = useState("dashboard");
  const [loading, setLoading] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const [unreadCount, setUnreadCount] = useState(0);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  const [dashboardData, setDashboardData] = useState({
    todayRegistrations: 0,
    todayPercentChange: 0,
    totalRevenue: 0,
    todayRevenue: 0,
    weekRegistrations: 0,
    weekPercentChange: 0,
    paidVsUnpaid: { paid: 12, unpaid: -1, percentage: 10 },
    upcomingTests: 2,
    nextTest: "Tomorrow",
    registrationTrend: {
      labels: ["Nov 1", "Nov 3", "Nov 4", "Nov 5"],
      data: [5, 7, 8, 6, 9, 12],
    },
    paymentFunnel: {
      registrations: 11,
      startedPayment: 0,
      completedPayment: 12,
      confirmed: 12,
    },
  });

  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth > 768) {
        setSidebarOpen(true);
      } else {
        setSidebarOpen(false);
      }
    };
    handleResize();
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  useEffect(() => {
    const isLoggedIn = localStorage.getItem("adminLoggedIn") === "true";
    const adminEmail = localStorage.getItem("adminEmail");
    if (!isLoggedIn || !adminEmail) {
      navigate("/admin-login");
      return;
    }
    if (activeTab === "dashboard") loadDashboardData();
  }, [navigate, activeTab]);

  const loadDashboardData = () => {
    setLoading(true);
    setTimeout(() => {
      setDashboardData({
        todayRegistrations: 0,
        todayPercentChange: 0,
        totalRevenue: 130050,
        todayRevenue: 0,
        weekRegistrations: 0,
        weekPercentChange: 0,
        paidVsUnpaid: { paid: 12, unpaid: -1, percentage: 10 },
        upcomingTests: 2,
        nextTest: "Tomorrow",
        registrationTrend: {
          labels: ["Nov 1", "Nov 3", "Nov 4", "Nov 5"],
          data: [5, 7, 8, 6, 9, 12],
        },
        paymentFunnel: {
          registrations: 11,
          startedPayment: 0,
          completedPayment: 12,
          confirmed: 12,
        },
      });
      setLoading(false);
    }, 500);
  };

  const handleLogout = () => {
    localStorage.removeItem("adminLoggedIn");
    localStorage.removeItem("adminEmail");
    navigate("/admin-login");
  };

  const toggleSidebar = () => setSidebarOpen((prev) => !prev);
  const handleSearch = (e) => setSearchQuery(e.target.value);
  const refreshDashboard = () => loadDashboardData();

  const handleTabChange = (tab) => {
    setActiveTab(tab);
    setMobileMenuOpen(false);
    if (window.innerWidth <= 768) setSidebarOpen(false);
  };

  // ── Stats cards ───────────────────────────────────────────────────────────
  const renderStatsCards = () => {
    const stats = [
      {
        title: "REGISTRATIONS TODAY",
        value: dashboardData.todayRegistrations,
        subValue: `${dashboardData.todayPercentChange}% from yesterday`,
        iconKey: "analytics",
        color: "stat-blue",
      },
      {
        title: "REGISTRATIONS THIS WEEK",
        value: dashboardData.weekRegistrations,
        subValue: `${dashboardData.weekPercentChange}% from last week`,
        iconKey: "notifications",
        color: "stat-purple",
      },
    ];
    return (
      <div className="stats-grid">
        {stats.map((stat, index) => (
          <div className={`stat-card ${stat.color}`} key={index}>
            <div className="stat-icon">{icons[stat.iconKey]("#0891b2")}</div>
            <div className="stat-content">
              <h3>{stat.title}</h3>
              <div className="stat-value">{stat.value}</div>
              <div className="stat-subvalue">{stat.subValue}</div>
            </div>
          </div>
        ))}
      </div>
    );
  };

  // ── Registration chart ────────────────────────────────────────────────────
  const renderRegistrationChart = () => {
    const maxValue = Math.max(...dashboardData.registrationTrend.data);
    return (
      <div className="chart-section">
        <div className="chart-header"><h3>Registrations Over Time</h3></div>
        <div className="chart-container">
          <div className="chart-bars">
            {dashboardData.registrationTrend.data.map((value, index) => {
              const percentage = (value / maxValue) * 100;
              return (
                <div className="chart-bar-container" key={index}>
                  <div className="chart-bar" style={{ height: `${percentage}%` }}>
                    <div className="bar-value">{value}</div>
                  </div>
                  <div className="chart-label">
                    {dashboardData.registrationTrend.labels[index]}
                  </div>
                </div>
              );
            })}</div>
        </div>
      </div>
    );
  };

  // ── Payment funnel ────────────────────────────────────────────────────────
  const renderPaymentFunnel = () => {
    const stages = [
      { label: "Registrations", value: dashboardData.paymentFunnel.registrations, percentage: 100 },
    ];
    return (
      <div className="funnel-section">
        <div className="funnel-header"><h3>Payment Conversion Funnel</h3></div>
        <div className="funnel-container">
          {stages.map((stage, index) => (
            <div className="funnel-stage" key={index}>
              <div className="stage-label">{stage.label}</div>
              <div className="stage-value">{stage.value} ({stage.percentage}%)</div>
              <div className="stage-bar" style={{ width: `${stage.percentage}%` }} />
            </div>
          ))}
        </div>
      </div>
    );
  };

  // ── Dashboard main content ────────────────────────────────────────────────
  const renderDashboardContent = () => (
    <div className="dashboard-content">
      <div className="welcome-section">
        <h2>Dashboard Overview</h2>
        <p>Here's an overview of your platform performance</p>
      </div>
      {renderStatsCards()}
      <div className="charts-grid">
        <div className="chart-card">{renderRegistrationChart()}</div>
        <div className="chart-card">{renderPaymentFunnel()}</div>
      </div>
      <div className="quick-access-section">
        <h3>Quick Actions</h3>
        <div className="quick-action-cards">
          <div className="quick-action-card" onClick={() => handleTabChange("university")}>
            <div className="quick-action-icon">{icons.university("#0891b2")}</div>
            <div className="quick-action-content">
              <h4>Import University Data</h4>
              <p>Import and manage university &amp; college data</p>
            </div>
            <div className="quick-action-arrow">→</div>
          </div>
          <div className="quick-action-card" onClick={() => handleTabChange("student-analytics")}>
            <div className="quick-action-icon">{icons.analytics("#8b5cf6")}</div>
            <div className="quick-action-content">
              <h4>Student Analytics</h4>
              <p>View university &amp; course selections by students</p>
            </div>
            <div className="quick-action-arrow">→</div>
          </div>
        </div>
      </div>
      <div className="action-section">
        <button className="refresh-btn" onClick={refreshDashboard}>
          Refresh Dashboard
        </button>
      </div>
    </div>
  );

  // ── Settings content ──────────────────────────────────────────────────────
  const renderSettingsContent = () => (
    <div className="settings-content">
      <div className="welcome-section">
        <h2>Settings</h2>
        <p>Configure your dashboard settings</p>
      </div>
      <div className="settings-grid">
        <div className="settings-card">
          <h3>General Settings</h3>
          <div className="settings-item">
            <label>Site Name</label>
            <input type="text" defaultValue="Admin Dashboard" />
          </div>
          <div className="settings-item">
            <label>Timezone</label>
            <select defaultValue="UTC">
              <option value="UTC">UTC</option>
              <option value="IST">IST</option>
              <option value="EST">EST</option>
            </select>
          </div>
        </div>
        <div className="settings-card">
          <h3>Notification Settings</h3>
          <div className="settings-item">
            <label><input type="checkbox" defaultChecked /> Email Notifications</label>
          </div>
          <div className="settings-item">
            <label><input type="checkbox" defaultChecked /> User Registration Alerts</label>
          </div>
        </div>
      </div>
    </div>
  );

  // ── Render content switch ─────────────────────────────────────────────────
  const renderContent = () => {
    switch (activeTab) {
      case "dashboard":         return renderDashboardContent();
      case "users":             return <AdminUserManagement />;
      case "university":        return <University />;
      case "bachelors":         return <Bachelors />;
      case "masters":           return <Masters />;
      case "phd":               return <PhD />;
      case "student-analytics": return <StudentAnalytics />;
      case "settings":          return renderSettingsContent();
      default:                  return renderDashboardContent();
    }
  };

  const getNavbarTitle = () => {
    const titles = {
      "dashboard":         "Dashboard",
      "users":             "Users",
      "university":        "University Data",
      "bachelors":         "Bachelors",
      "masters":           "Masters",
      "phd":               "PhD",
      "notifications":     "Notifications",
      "student-analytics": "Student Analytics",
      "settings":          "Settings",
    };
    return titles[activeTab] || "Dashboard";
  };

  if (loading && activeTab === "dashboard") {
    return (
      <div className="loading-container">
        <div className="loading-spinner" />
        <p>Loading dashboard...</p>
      </div>
    );
  }

  // ── Sidebar menu item ─────────────────────────────────────────────────────
  const MenuItem = ({ tab, iconKey, label, badge }) => {
    const isActive = activeTab === tab;
    const iconColor = isActive ? "#1e40af" : "#64748b";
    return (
      <li
        className={isActive ? "active" : ""}
        onClick={() => handleTabChange(tab)}
      >
        <span className="menu-icon">
          {icons[iconKey](iconColor)}
          {badge > 0 && <span className="notification-badge-sidebar">{badge}</span>}
        </span>
        {sidebarOpen && (
          <>
            <span className="menu-label">{label}</span>
            {badge > 0 && <span className="notification-count-sidebar">{badge}</span>}
          </>
        )}
      </li>
    );
  };

  // ── Mobile bottom nav items ───────────────────────────────────────────────
  const mobileNavItems = [
    { tab: "dashboard",         iconKey: "dashboard",      label: "Home" },
    { tab: "users",             iconKey: "users",          label: "Users" },
    { tab: "university",        iconKey: "university",     label: "Uni" },
    { tab: "student-analytics", iconKey: "analytics",      label: "Analytics" },
    { tab: "notifications",     iconKey: "notifications",  label: "Alerts", badge: unreadCount },
  ];

  return (
    <div className="admin-dashboard">

      {/* Mobile overlay backdrop */}
      {sidebarOpen && (
        <div className="sidebar-backdrop" onClick={() => setSidebarOpen(false)} />
      )}

      {/* Sidebar */}
      <div className={`sidebar ${sidebarOpen ? "open" : "closed"}`}>

        {/* ── White logo strip ── */}
        <div className="sidebar-logo-strip">
          {sidebarOpen && (
            <img src={LOGO_URI} alt="EduTech" className="sidebar-logo" />
          )}
          {!sidebarOpen && (
            <div className="sidebar-logo-icon">
              {icons.dashboard("#1e40af")}
            </div>
          )}
          <button className="sidebar-toggle" onClick={toggleSidebar} aria-label="Toggle sidebar">
            {sidebarOpen ? icons.collapse : icons.expand}
          </button>
        </div>

        {/* Nav section label */}
        {sidebarOpen && <div className="nav-section-label">Main Menu</div>}

        <ul className="sidebar-menu">
          <MenuItem tab="dashboard"         iconKey="dashboard"      label="Dashboard"        />
          <MenuItem tab="users"             iconKey="users"          label="Users"             />
          <MenuItem tab="university"        iconKey="university"     label="University Data"   />

          {sidebarOpen && <li className="menu-divider" />}

          <MenuItem tab="bachelors"         iconKey="bachelors"      label="Bachelors"         />
          <MenuItem tab="masters"           iconKey="masters"        label="Masters"           />
          <MenuItem tab="phd"              iconKey="phd"            label="PhD"               />

          {sidebarOpen && <li className="menu-divider" />}

          <MenuItem tab="student-analytics" iconKey="analytics"      label="Student Analytics" />
          <MenuItem
            tab="notifications"
            iconKey="notifications"
            label="Notifications"
            badge={unreadCount}
          />
          <MenuItem tab="settings"          iconKey="settings"       label="Settings"          />
        </ul>

        <div className="sidebar-footer">
          <button className="logout-btn" onClick={handleLogout}>
            <span className="menu-icon">{icons.logout}</span>
            {sidebarOpen && <span>Logout</span>}
          </button>
        </div>
      </div>

      {/* Main Content */}
      <div className="main-content">

        {/* Top Navbar */}
        <nav className="navbar">
          <div className="navbar-left">
            <button className="hamburger-btn" onClick={toggleSidebar} aria-label="Open menu">
              {icons.hamburger}
            </button>
            <h1>{getNavbarTitle()}</h1>
          </div>
          <div className="navbar-center">
            <div className="search-container">
              <input
                type="text"
                placeholder="Search..."
                value={searchQuery}
                onChange={handleSearch}
                className="search-input"
              />
              <button className="search-btn">{icons.search}</button>
            </div>
          </div>
          <div className="navbar-right">
            <Notifications
              adminId={localStorage.getItem("adminEmail")}
              onUnreadCountChange={setUnreadCount}
            />
            <div className="admin-profile">
              <span className="profile-icon">
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                  <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/>
                  <circle cx="12" cy="7" r="4"/>
                </svg>
              </span>
              <span className="profile-name">
                {localStorage.getItem("adminEmail")?.split("@")[0] || "Admin"}
              </span>
            </div>
          </div>
        </nav>

        {/* Content Area */}
        <div className="content-area">
          {activeTab === "notifications" ? (
            <div className="notifications-page">
              <div className="notifications-header">
                <h2>Notifications</h2>
                <p>Manage and view all your notifications here</p>
              </div>
              <Notifications
                adminId={localStorage.getItem("adminEmail")}
                fullView={true}
                onUnreadCountChange={setUnreadCount}
              />
            </div>
          ) : (
            renderContent()
          )}
        </div>

        <footer className="dashboard-footer">
          <p>© {new Date().getFullYear()} Admin Dashboard. All rights reserved.</p>
        </footer>
      </div>

      {/* Mobile Bottom Navigation */}
      <nav className="mobile-bottom-nav">
        {mobileNavItems.map(({ tab, iconKey, label, badge }) => (
          <button
            key={tab}
            className={`mobile-nav-btn ${activeTab === tab ? "active" : ""}`}
            onClick={() => handleTabChange(tab)}
          >
            <span className="mobile-nav-icon">
              {icons[iconKey](activeTab === tab ? "#4a90e2" : "#94a3b8")}
              {badge > 0 && <span className="mobile-nav-badge">{badge > 99 ? "99+" : badge}</span>}
            </span>
            <span className="mobile-nav-label">{label}</span>
          </button>
        ))}
        <button className="mobile-nav-btn" onClick={toggleSidebar}>
          <span className="mobile-nav-icon">{icons.hamburger}</span>
          <span className="mobile-nav-label">More</span>
        </button>
      </nav>

    </div>
  );
};

export default AdminDashboard;